content.text:
/* Custom CSS for External ID sign-in page */
/* Upload this file via portal: External Identities → Custom branding → Custom CSS */

/* Override the sign-in box background */
.login-panel {
  background-color: rgba(255, 255, 255, 0.95) !important;
  border-radius: 12px !important;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3) !important;
}

/* Apply brand font (must be hosted on your CDN) */
@import url('https://cdn.contoso.com/fonts/contoso-sans.css');
body, input, button {
  font-family: 'ContosoSans', system-ui, sans-serif !important;
}

/* Brand primary color for the sign-in button */
#idSIButton9, .btn-primary {
  background-color: #7c3aed !important;
  border-color: #7c3aed !important;
}
#idSIButton9:hover, .btn-primary:hover {
  background-color: #6d28d9 !important;
}

/* Hide the 'Sign in with Microsoft' branding text */
.ext-sign-in-box .brand-banner {
  display: none !important;
}

/* Move the logo to center alignment */
.logo-text, .header-logo {
  display: flex;
  justify-content: center;
}

terraform {
  required_providers {
    azuread = {
      source  = "hashicorp/azuread"
      version = "~> 2.50"
    }
  }
}

# Default organizational branding
resource "azuread_directory_setting" "branding_settings" {
  template_id = data.azuread_directory_setting_template.branding.id
  values {
    name  = "EnableMIPLabels"
    value = "true"
  }
}

# Note: Full branding asset upload typically done via Graph API calls
# invoked from null_resource local-exec provisioners
resource "null_resource" "upload_banner_logo" {
  triggers = {
    logo_hash = filemd5("${path.module}/assets/banner-logo.png")
  }
  provisioner "local-exec" {
    command = <<-EOT
      az rest --method PUT \
        --uri 'https://graph.microsoft.com/v1.0/organization/${var.tenant_id}/branding/bannerLogo' \
        --body @assets/banner-logo.png \
        --headers 'Content-Type=image/png'
    EOT
  }
}
